import base64


def is_base64(s: str, url_safe: bool = False) -> bool:
    """
    判断字符串是否为合法的 Base64 编码
    :param s: 待判断的字符串
    :param url_safe: 是否为 URL 安全的 Base64（使用 -_ 替代 +/）
    :return: True/False
    """
    if len(s) < 500:
        return False
    # 空字符串直接排除
    if not isinstance(s, str) or len(s) == 0:
        return False

    # 1. 过滤可能的合法换行（Base64 允许分段，换行符不影响）
    s_clean = s.replace('\n', '').replace('\r', '')
    length = len(s_clean)

    # 2. 检查长度是否为 4 的整数倍
    if length % 4 != 0:
        return False

    # 3. 定义合法字符集
    if url_safe:
        valid_chars = set('ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_=')
    else:
        valid_chars = set('ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=')

    # 4. 检查所有字符是否合法
    for char in s_clean:
        if char not in valid_chars:
            return False

    # 5. 检查 = 仅出现在末尾，且数量 ≤2
    eq_count = s_clean.count('=')
    if eq_count > 2 or (eq_count > 0 and not s_clean.endswith('=' * eq_count)):
        return False

    # 6. 尝试解码（最终验证，避免格式合法但无效的情况）
    try:
        if url_safe:
            # URL 安全 Base64 解码需先替换 -/_ 为 +/
            s_decode = s_clean.replace('-', '+').replace('_', '/')
            base64.b64decode(s_decode)
        else:
            base64.b64decode(s_clean)
        return True
    except base64.binascii.Error:
        return False


# 测试示例
if __name__ == "__main__":
    # 合法示例
    print(is_base64('aGVsbG8gd29ybGQ='))  # 标准 Base64（hello world）→ True
    print(is_base64('aGVsbG8gd29ybGQ', url_safe=True))  # URL 安全（无填充）→ True
    # 非法示例
    print(is_base64('aGVsbG8='))  # 格式合法但解码失败？不，实际是 hello → True（有效）
    print(is_base64('aaaaaa=='))  # 格式合法，解码也能过（但无业务意义）→ True
    print(is_base64('aGVsbG8='))  # 长度 6（6%4=2）→ False
    print(is_base64(''))  # 含非法字符 → False
    print(is_base64(''))  # = 不在末尾 → False
    print(is_base64('crazycredits'))  # = 不在末尾 → False